"use strict";(globalThis.webpackChunkdocs=globalThis.webpackChunkdocs||[]).push([[418],{2480(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","href":"/PrefabCache/","label":"Introduction","docId":"introduction","unlisted":false},{"type":"link","href":"/PrefabCache/installation","label":"Installation","docId":"installation","unlisted":false},{"type":"category","label":"Guide","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/PrefabCache/tutorial/Create","label":"Create","docId":"tutorial/Create","unlisted":false},{"type":"link","href":"/PrefabCache/tutorial/GetPrefab","label":"GetPrefab","docId":"tutorial/GetPrefab","unlisted":false},{"type":"link","href":"/PrefabCache/tutorial/ReturnPrefab","label":"ReturnPrefab","docId":"tutorial/ReturnPrefab","unlisted":false},{"type":"link","href":"/PrefabCache/tutorial/SetCacheParent","label":"SetCacheParent","docId":"tutorial/SetCacheParent","unlisted":false},{"type":"link","href":"/PrefabCache/tutorial/Expand","label":"Expand","docId":"tutorial/Expand","unlisted":false},{"type":"link","href":"/PrefabCache/tutorial/Dispose","label":"Dispose","docId":"tutorial/Dispose","unlisted":false}],"href":"/PrefabCache/category/guide"}]},"docs":{"installation":{"id":"installation","title":"Installation","description":"You\u2019ve got three options to install PrefabCache into your project:","sidebar":"tutorialSidebar"},"introduction":{"id":"introduction","title":"Introduction","description":"PrefabCache is a generic, lightweight object-pooling library for Roblox. It lets you pre-create clones of any Instance and reuse them on demand instead of calling Instance.new or Clone every frame, keeping your game\'s memory allocation predictable and your frame times smooth.","sidebar":"tutorialSidebar"},"tutorial/Create":{"id":"tutorial/Create","title":"Create","description":"Factory method to create a new PrefabCache instance. It clones the given template, pre-creates a pool of instances, and returns a ready-to-use cache.","sidebar":"tutorialSidebar"},"tutorial/Dispose":{"id":"tutorial/Dispose","title":"Dispose","description":"Destroys all pooled instances (both available and in-use), destroys the internal template, and marks the cache as disposed. After disposal, calling any public method (GetPrefab, ReturnPrefab, SetCacheParent, Expand) will throw an error.","sidebar":"tutorialSidebar"},"tutorial/Expand":{"id":"tutorial/Expand","title":"Expand","description":"Manually expands the pool by creating additional instances. If count is omitted, ExpansionSize is used. This is useful for pre-warming the cache before a known spike in demand.","sidebar":"tutorialSidebar"},"tutorial/GetPrefab":{"id":"tutorial/GetPrefab","title":"GetPrefab","description":"Retrieves an instance from the pool. If the pool is empty, it will automatically expand by ExpansionSize before returning an instance. The optional onGet callback is executed before the instance is returned.","sidebar":"tutorialSidebar"},"tutorial/ReturnPrefab":{"id":"tutorial/ReturnPrefab","title":"ReturnPrefab","description":"Returns an instance back to the pool, making it available for future GetPrefab calls. The instance\'s parent is reset to CurrentCacheParent. The optional onReturn callback is executed before the instance is stored.","sidebar":"tutorialSidebar"},"tutorial/SetCacheParent":{"id":"tutorial/SetCacheParent","title":"SetCacheParent","description":"Changes the parent of all cached instances, both available and currently in use. This is useful for moving pooled objects between containers at runtime.","sidebar":"tutorialSidebar"}}}}')}}]);